// jobStatusStripe maps a job status to the task-row-status-* class so the
// detail header reuses the task list's left-edge colour palette.
//
//	pending   → slate (same as task pending)
//	running   → green (same as task executing)
//	completed → gray  (same as task done)
//	failed    → red   (same as task aborted)
func jobStatusStripe(status string) string {
	switch status {
	case "running":
		return "task-row-status-executing"
	case "completed":
		return "task-row-status-done"
	case "failed":
		return "task-row-status-aborted"
	default:
		return "task-row-status-pending"
	}
}

